from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Cloud SQL Instance Connection Name
DB_NAME = 'your-cloudsql-instance-name'
DB_USER = 'your-mysql-username'
DB_PASSWORD = 'your-mysql-password'

# SQLAlchemy configuration
app.config['SQLALCHEMY_DATABASE_URI'] = f'mysql+pymysql://{DB_USER}:{DB_PASSWORD}@/{DB_NAME}'
db = SQLAlchemy(app)

class Item(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)
    description = db.Column(db.String(200), nullable=False)

@app.route('/search', methods=['GET'])
def search():
    query_params = request.args
    query = ''
    
    # Dynamic SQL query construction using string concatenation
    if 'name' in query_params:
        query += f" AND name LIKE '%{query_params['name']}%'"
    
    if 'description' in query_params:
        query += f" AND description LIKE '%{query_params['description']}%'"
    
    # Limit the number of results to 100
    limit = 100
    
    try:
        results = Item.query.filter(query).limit(limit).all()
        return jsonify([item.name for item in results])
    except Exception as e:
        return jsonify({"error": str(e)}), 500

